                httpClient.DefaultRequestHeaders.TryAddWithoutValidation(key, value);

            var cfg = new ThoughtSpot.Client.Client.Configuration { BasePath = config.Host.TrimEnd('/') };

            if (config.TokenProvider is not null)
            {
                tokenProvider = config.TokenProvider;
            }
            else if (config.BearerToken is not null)
            {
#pragma warning disable CS0618
                tokenProvider = () => System.Threading.Tasks.Task.FromResult(config.BearerToken);
#pragma warning restore CS0618
            }
            else
            {
                var tokenRequest = new ThoughtSpot.Client.Model.GetFullAccessTokenRequest(
                    username:          config.Username!,
                    password:          config.Password,
                    secretKey:         config.SecretKey,
                    validityTimeInSec: config.TokenValiditySeconds);

                var authApi = new ThoughtSpot.Client.Api.AuthenticationApi(httpClient, cfg, handler);

                var first = await authApi.GetFullAccessTokenAsync(
                    tokenRequest, cancellationToken: cancellationToken);

                var cachedToken = first.VarToken
                    ?? throw new InvalidOperationException("Auth succeeded but token was null.");

                var expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds - 30);

                tokenProvider = async () =>
                {
                    if (DateTimeOffset.UtcNow < expiresAt)
                        return cachedToken;

                    expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds);

                    var refreshed = await authApi.GetFullAccessTokenAsync(tokenRequest);
                    cachedToken = refreshed.VarToken
                        ?? throw new InvalidOperationException("Token refresh returned null.");
                    expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds - 30);
                    return cachedToken;
                };
            }

            return new CustomActionApi(httpClient, cfg, handler);
